# ---------------------------------------------------------------------------
# normalize_location
# ---------------------------------------------------------------------------
class TestNormalizeLocation:
    def test_returns_country_and_subdivision_tuple(self, sm):
        # Despite the docstring ("Returns: Normalized location string"),
        # the function actually returns a (country, subdivision) tuple.
        with patch.object(
            sm.location_tools, "get_country_and_subdivision",
            return_value=("US", "US-VA"),
        ) as gcs:
            result = sm.normalize_location("Richmond", "United States")
        assert result == ("US", "US-VA")
        gcs.assert_called_once_with("United States", "Richmond")

    def test_forwards_arguments_in_expected_order(self, sm):
        with patch.object(
            sm.location_tools, "get_country_and_subdivision",
            return_value=("HK", "HK"),
        ) as gcs:
            sm.normalize_location("Hong Kong", "China")
        # country is passed first, location second
        gcs.assert_called_once_with("China", "Hong Kong")


