class TestMakeStrainId:
    def test_id_format(self, sm, fake_config):
        taxon = {"usage_id": "3F72J"}
        with patch.dict(sm.package_config, fake_config, clear=True), \
             patch.object(sm.host_tools, "match_species", return_value=taxon) as ms:
            result = sm.make_strain_id(
                host="Chicken", month="02", sequence="15", lab_id="MN.26A"
            )
        # Format built by the code: {usage_id}.{version}-{sequence}-{lab_id}-{month}
        assert result == "3F72J.1-15-MN.26A-02"
        ms.assert_called_once_with("Chicken", "COL2026")

    def test_uses_dataset_key_from_config(self, sm, fake_config):
        cfg = dict(fake_config, COL_dataset_key="OTHERKEY")
        with patch.dict(sm.package_config, cfg, clear=True), \
             patch.object(sm.host_tools, "match_species",
                          return_value={"usage_id": "X"}) as ms:
            sm.make_strain_id("Duck", "07", "3", "LAB")
        ms.assert_called_once_with("Duck", "OTHERKEY")


# ---------------------------------------------------------------------------
# assemble_strain_name
# ---------------------------------------------------------------------------
class TestAssembleStrainName:
    """
    These tests patch every external touchpoint:
        - requests.Session (context manager)
        - host_tools.scientific_to_vernacular
        - host_tools.match_species
        - location_tools.get_country_and_subdivision
        - package_config
    """

    def _patched(self, sm, fake_config, *, vernacular, subdivision, usage_id="3F72J"):
        """Return a contextmanager stack set up with the given return values."""
        cm = patch.multiple(
            sm.host_tools,
            scientific_to_vernacular=MagicMock(return_value=vernacular),
            match_species=MagicMock(return_value={"usage_id": usage_id}),
        )
        loc = patch.object(
            sm.location_tools, "get_country_and_subdivision",
            return_value=("US", subdivision),
        )
        cfg = patch.dict(sm.package_config, fake_config, clear=True)
        # requests.Session() used as a context manager -> return a dummy
        sess = patch.object(sm.requests, "Session", return_value=_DummySession())
        return cm, loc, cfg, sess

    def test_non_human_host_included(self, sm, fake_config):
        cm, loc, cfg, sess = self._patched(
            sm, fake_config, vernacular="Chicken", subdivision="US-VA"
        )
        with cm, loc, cfg, sess:
            name = sm.assemble_strain_name(
                virus_type="A",
                host="Gallus gallus",
                location="Richmond",
                country="US",
                sequence="02",
                lab_id="MN.26A",
                collection_date=datetime(2026, 2, 15),
            )
        assert name == "A/Chicken/US-VA/3F72J.1-02-MN.26A-02/2026"

    def test_human_host_dropped(self, sm, fake_config):
        cm, loc, cfg, sess = self._patched(
            sm, fake_config, vernacular="Human", subdivision="US-NY"
        )
        with cm, loc, cfg, sess:
            name = sm.assemble_strain_name(
                virus_type="H1N1",
                host="Human",
                location="New York",
                country="US",
                sequence="042",
                lab_id="NYSDOH",
                collection_date=datetime(2026, 11, 3),
            )
        # No host segment for human samples
        assert name == "H1N1/US-NY/3F72J.1-042-NYSDOH-11/2026"

    def test_month_zero_padded(self, sm, fake_config):
        cm, loc, cfg, sess = self._patched(
            sm, fake_config, vernacular="Swine", subdivision="US-IA"
        )
        with cm, loc, cfg, sess:
            name = sm.assemble_strain_name(
                virus_type="H3N2",
                host="Sus scrofa",
                location="Ames",
                country="US",
                sequence="9",
                lab_id="LAB",
                collection_date=datetime(2026, 1, 5),  # month 1 -> "01"
            )
        assert "-01/2026" in name

    def test_empty_subdivision_segment_dropped(self, sm, fake_config):
        # If the location tool yields an empty subdivision string, that
        # component is filtered out by the `if c` comprehension.
        cm, loc, cfg, sess = self._patched(
            sm, fake_config, vernacular="Chicken", subdivision=""
        )
        with cm, loc, cfg, sess:
            name = sm.assemble_strain_name(
                virus_type="A",
                host="Gallus gallus",
                location="Nowhere",
                country="US",
                sequence="1",
                lab_id="LAB",
                collection_date=datetime(2026, 6, 1),
            )
        parts = name.split("/")
        assert "" not in parts
        assert parts[0] == "A"
        assert parts[1] == "Chicken"

    def test_none_vernacular_should_be_treated_as_human(self, sm, fake_config):
        cm, loc, cfg, sess = self._patched(
            sm, fake_config, vernacular=None, subdivision="US-VA"
        )
        with cm, loc, cfg, sess:
            name = sm.assemble_strain_name(
                virus_type="A",
                host="Unknown",
                location="Richmond",
                country="US",
                sequence="1",
                lab_id="LAB",
                collection_date=datetime(2026, 2, 1),
            )
        # Intended behavior: no host segment.
        assert name.startswith("A/US-VA/")

    def test_scientific_to_vernacular_called_with_session(self, sm, fake_config):
        s2v = MagicMock(return_value="Chicken")
        loc = patch.object(
            sm.location_tools, "get_country_and_subdivision",
            return_value=("US", "US-VA"),
        )
        cfg = patch.dict(sm.package_config, fake_config, clear=True)
        dummy = _DummySession()
        with patch.object(sm.host_tools, "scientific_to_vernacular", s2v), \
             patch.object(sm.host_tools, "match_species",
                          return_value={"usage_id": "X"}), \
             loc, cfg, \
             patch.object(sm.requests, "Session", return_value=dummy):
            sm.assemble_strain_name(
                virus_type="A",
                host="Gallus gallus",
                location="Richmond",
                country="US",
                sequence="1",
                lab_id="LAB",
                collection_date=datetime(2026, 2, 1),
            )
        # host passed positionally, session passed as keyword
        args, kwargs = s2v.call_args
        assert args[0] == "Gallus gallus"
        assert kwargs["session"] is dummy


