# CLI: parse_args / run_single / run_file
# ---------------------------------------------------------------------------
class TestParseArgs:
    def test_single_mode_parses_required(self, sm, monkeypatch):
        argv = [
            "strain-gen", "single",
            "-v", "H1N1",
            "--human",
            "-l", "New York",
            "-c", "US",
            "-n", "042",
            "-b", "NYSDOH",
            "-d", "2026-11-03",
        ]
        monkeypatch.setattr(sys, "argv", argv)
        args = sm.parse_args()
        assert args.mode == "single"
        assert args.virus_type == "H1N1"
        assert args.human is True
        assert args.date == "2026-11-03"

    def test_file_mode_defaults(self, sm, monkeypatch):
        argv = ["strain-gen", "file", "-i", "in.csv"]
        monkeypatch.setattr(sys, "argv", argv)
        args = sm.parse_args()
        assert args.mode == "file"
        assert args.input == "in.csv"
        assert args.output is None
        assert args.strain_column == "strain_name"

    def test_missing_mode_exits(self, sm, monkeypatch):
        monkeypatch.setattr(sys, "argv", ["strain-gen"])
        with pytest.raises(SystemExit):
            sm.parse_args()

    def test_single_missing_required_exits(self, sm, monkeypatch):
        # missing --date
        argv = ["strain-gen", "single", "-v", "H1N1", "--human",
                "-l", "NY", "-c", "US", "-n", "1", "-b", "LAB"]
        monkeypatch.setattr(sys, "argv", argv)
        with pytest.raises(SystemExit):
            sm.parse_args()


class TestRunSingle:
    def _args(self, **over):
        base = dict(
            human=True, host=None, virus_type="H1N1", location="NY",
            country="US", sequence="1", lab_id="LAB", date="2026-02-15",
        )
        base.update(over)
        return SimpleNamespace(**base)

    def test_requires_host_or_human(self, sm):
        args = self._args(human=False, host=None)
        with pytest.raises(SystemExit) as exc:
            sm.run_single(args)
        assert "--host is required" in str(exc.value)

    def test_bad_date_format_exits(self, sm):
        args = self._args(date="15-02-2026")
        with pytest.raises(SystemExit) as exc:
            sm.run_single(args)
        assert "YYYY-MM-DD" in str(exc.value)

    def test_calls_assemble_and_prints(self, sm, capsys):
        args = self._args()
        with patch.object(sm, "assemble_strain_name",
                          return_value="A/US-NY/ID/2026") as asm:
            sm.run_single(args)
        out = capsys.readouterr().out.strip()
        assert out == "A/US-NY/ID/2026"
        # human=True -> host forwarded as "Human"
        assert asm.call_args.kwargs["host"] == "Human"
        assert isinstance(asm.call_args.kwargs["collection_date"], datetime)

    def test_host_forwarded_when_not_human(self, sm, capsys):
        args = self._args(human=False, host="Avian")
        with patch.object(sm, "assemble_strain_name", return_value="X") as asm:
            sm.run_single(args)
        assert asm.call_args.kwargs["host"] == "Avian"


class TestRunFile:
    def _args(self, **over):
        base = dict(input="in.csv", output=None, strain_column="strain_name")
        base.update(over)
        return SimpleNamespace(**base)

    def test_defaults_output_to_input(self, sm, capsys):
        args = self._args()
        with patch.object(sm, "process_csv", return_value=(3, [])) as pc:
            sm.run_file(args)
        assert pc.call_args.kwargs["output_path"] == "in.csv"
        err = capsys.readouterr().err
        assert "Wrote 3 strain name(s) to in.csv" in err

    def test_uses_explicit_output(self, sm, capsys):
        args = self._args(output="out.csv")
        with patch.object(sm, "process_csv", return_value=(2, [])) as pc:
            sm.run_file(args)
        assert pc.call_args.kwargs["output_path"] == "out.csv"

    def test_reports_skipped_rows(self, sm, capsys):
        args = self._args()
        errors = [(4, "missing country"), (7, "bad date")]
        with patch.object(sm, "process_csv", return_value=(1, errors)):
            sm.run_file(args)
        err = capsys.readouterr().err
        assert "Skipped 2 row(s)" in err
        assert "Row 4: missing country" in err
        assert "Row 7: bad date" in err

    def test_file_not_found_exits(self, sm):
        args = self._args()
        with patch.object(sm, "process_csv", side_effect=FileNotFoundError("nope")):
            with pytest.raises(SystemExit) as exc:
                sm.run_file(args)
        assert "nope" in str(exc.value)

    def test_value_error_exits(self, sm):
        args = self._args()
        with patch.object(sm, "process_csv",
                          side_effect=ValueError("missing columns")):
            with pytest.raises(SystemExit) as exc:
                sm.run_file(args)
        assert "missing columns" in str(exc.value)


class TestMain:
    def test_dispatches_single(self, sm, monkeypatch):
        monkeypatch.setattr(sm, "parse_args",
                            lambda: SimpleNamespace(mode="single"))
        with patch.object(sm, "run_single") as rs, \
             patch.object(sm, "run_file") as rf:
            sm.main()
        rs.assert_called_once()
        rf.assert_not_called()

    def test_dispatches_file(self, sm, monkeypatch):
        monkeypatch.setattr(sm, "parse_args",
                            lambda: SimpleNamespace(mode="file"))
        with patch.object(sm, "run_single") as rs, \
             patch.object(sm, "run_file") as rf:
            sm.main()
        rf.assert_called_once()
        rs.assert_not_called()


